import { Component } from '@angular/core';
import { BackendService } from '../services/backend.service';

@Component({
  selector: 'app-login',
  standalone: false,
  templateUrl: './login.component.html',
  styleUrls: ['./login.component.css']
})
export class LoginComponent {
  email = '';
  password = '';

  constructor(private backend: BackendService) {}

  login() {
    const payload = { correo: this.email, password: this.password };
    this.backend.login(payload).subscribe({
      next: (res: any) => alert(res.mensaje || 'Inicio de sesión correcto'),
      error: () => alert('No se pudo conectar con el backend')
    });
  }
}
<div class="background">
  <div class="login-card">
    <h1>Skill Swap</h1>
    <h2>Iniciar sesión</h2>
    <p>Comparte conocimientos, aprende nuevas habilidades.</p>

    <form (ngSubmit)="login()">
      <input type="email" placeholder="Correo electrónico" [(ngModel)]="email" name="email">
      <input type="password" placeholder="Contraseña" [(ngModel)]="password" name="password">
      <button type="submit">Ingresar</button>
      <a href="#">¿Olvidaste tu contraseña?</a>
      <span>¿No tienes cuenta? <a routerLink="/registro">Crear cuenta</a></span>
    </form>
  </div>
</div>
